ServiceImpl

public Result login(LoginFormDTO loginForm, HttpSession session) &#123;  	//获取前端输入的手机号    String phone = loginForm.getPhone();      //获取前端输入的验证码    String loginCode = loginForm.getCode();      if (RegexUtils.isPhoneInvalid(phone)) &#123;          return Result.fail(&quot;手机号错误&quot;);      &#125;     //从redis获取后端生成的验证码      String redisCode = stringRedisTemplate.opsForValue().get(SystemContext.LOGIN_CODE + phone);      //前后端验证码不一致时      if(!loginCode.equals(redisCode))      &#123;          return Result.fail(&quot;验证码错误&quot;);      &#125;      //根据手机号从数据库查询用户      User user = query().eq(&quot;phone&quot;, phone).one();      //用户不存在，创建用户并保存到数据库    if (user == null) &#123;          user = creatUserWithPhone(phone);      &#125;      //生成token      String token = UUID.randomUUID().toString();      //存储token和user信息到redis	stringRedisTemplate.opsForValue().set(SystemContext.LOGIN_TOKEN + token, JSONUtil.toJsonStr(user),2,TimeUnit.HOURS);      return Result.ok(token);  &#125;
拦截器拦截用于延期Token的刷新拦截器public class RefreshTokenInterceptor implements HandlerInterceptor &#123;      @Resource      private StringRedisTemplate stringRedisTemplate;      @Override      public boolean preHandle(HttpServletRequest request, HttpServletResponse response, Object handler) throws Exception &#123;          log.info(&quot;拦截器拦截&quot;);        //从请求中获取token          String token = request.getHeader(&quot;authorization&quot;);          if (StringUtils.isEmpty(token) || &quot;undefined&quot;.equals(token)) &#123;              //不存在token            //放行到登录校验拦截器(以下都是)            return true;          &#125;          log.info(&quot;获得的token:&#123;&#125;&quot;,token);          //获取user的json字符串        String userStr = stringRedisTemplate.opsForValue().get(SystemContext.LOGIN_TOKEN + token);          //转换成user对象        User user = JSONUtil.toBean(userStr,User.class);          log.info(&quot;拦截到user:&#123;&#125;&quot;,user);          if (user == null) &#123;              return true;          &#125;          //把user转换成userDTO并保存到ThreadLocal        UserDTO userDTO = getUserDTOAndSaveToThreadLocal(user);          log.info(&quot;保存用户:&#123;&#125;到ThreadLocal&quot;,userDTO);          //续期Token        stringRedisTemplate.expire(SystemContext.LOGIN_TOKEN + token,2, TimeUnit.HOURS);          return true;      &#125;        @NotNull      private static UserDTO getUserDTOAndSaveToThreadLocal(User user) &#123;          UserDTO userDTO = new UserDTO();          userDTO.setId(user.getId());          userDTO.setNickName(user.getNickName());          userDTO.setIcon(user.getIcon());          UserHolder.saveUser(userDTO);          return userDTO;      &#125;  &#125;
校验登录拦截器public class LoginInterceptor implements HandlerInterceptor &#123;      @Resource      private StringRedisTemplate stringRedisTemplate;        @Override      public void afterCompletion(HttpServletRequest request, HttpServletResponse response, Object handler, @Nullable Exception ex) throws Exception &#123;          log.info(&quot;ThreadLocal清除用户&quot;);          UserHolder.removeUser();      &#125;          @Override      public boolean preHandle(HttpServletRequest request, HttpServletResponse response, Object handler) throws Exception &#123;  	    //从ThreadLocal里面查询用户        if (UserHolder.getUser() == null) &#123;              response.setStatus(401);              return false;          &#125;          //          return true;      &#125;
注册拦截器public class MvcConfig implements WebMvcConfigurer &#123;      @Resource      private LoginInterceptor loginInterceptor;      @Resource      private RefreshTokenInterceptor refreshTokenInterceptor;        @Override      public void addInterceptors(InterceptorRegistry registry) &#123;          log.info(&quot;加载拦截器&quot;);          registry.addInterceptor(loginInterceptor)                  .excludePathPatterns(                          &quot;/user/code&quot;,    // 发送验证码接口                          &quot;/user/login&quot;,   // 登录接口                          &quot;/blog/hot&quot;,     // 首页热门博客                          &quot;/shop/**&quot;,      // 店铺信息                          &quot;/shop-type/**&quot;, // 店铺分类                          &quot;/upload/**&quot;,                          &quot;/voucher/**&quot;                          )                  .order(1);          registry.addInterceptor(refreshTokenInterceptor).addPathPatterns(&quot;/**&quot;).order(0);      &#125;  &#125;
